import type { CareerQuestion } from "./rrt-questions";

export const sonographyQuestionsBatch8: CareerQuestion[] = [
  { id: "sono-606", stem: "A hyperechoic liver mass with posterior acoustic shadowing in a patient with cirrhosis most likely represents:", options: ["Hepatocellular carcinoma with calcification","Simple hepatic cyst","Hemangioma","Focal nodular hyperplasia"], correctIndex: 0, rationale: "In cirrhotic livers, a hyperechoic mass with calcification and shadowing raises concern for HCC. Calcification occurs in 5-10% of HCC cases. Surveillance with ultrasound every 6 months is recommended for cirrhotic patients.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-607", stem: "The sonographic hallmark of a cavernous hemangioma of the liver is:", options: ["Well-defined, homogeneously hyperechoic mass with posterior acoustic enhancement","Hypoechoic mass with irregular borders","Target sign with hypoechoic rim","Complex cystic mass with internal debris"], correctIndex: 0, rationale: "Cavernous hemangioma is the most common benign liver tumor. Classic appearance is a well-defined, homogeneously hyperechoic lesion <3cm with posterior enhancement. Atypical hemangiomas may be hypoechoic or heterogeneous.", difficulty: 1, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-608", stem: "Focal nodular hyperplasia (FNH) on ultrasound typically demonstrates:", options: ["Isoechoic to slightly hypoechoic mass with a central stellate scar that is hyperechoic","Anechoic mass with through-transmission","Diffusely calcified mass","Target appearance with necrotic center"], correctIndex: 0, rationale: "FNH is the second most common benign liver tumor. It appears isoechoic or slightly hypo/hyperechoic with a central scar (seen in ~20% on US). On Doppler, a central feeding artery with spoke-wheel pattern is characteristic.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-609", stem: "Hepatic steatosis (fatty liver) on ultrasound is characterized by:", options: ["Diffusely increased hepatic echogenicity compared to the renal cortex with beam attenuation","Decreased hepatic echogenicity","Normal echogenicity with calcifications","Heterogeneous echo pattern with multiple cysts"], correctIndex: 0, rationale: "Fatty liver shows increased parenchymal echogenicity (brighter than kidney), poor visualization of diaphragm and deep hepatic structures due to attenuation, and poor delineation of intrahepatic vessels.", difficulty: 1, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-610", stem: "A 'bull's-eye' or target lesion pattern in the liver most commonly suggests:", options: ["Hepatic metastasis","Simple cyst","Hemangioma","Focal nodular hyperplasia"], correctIndex: 0, rationale: "The target or bull's-eye sign (hypoechoic halo surrounding an echogenic center) is most commonly associated with hepatic metastases, particularly from GI malignancies. The halo represents compressed liver parenchyma or tumor growth.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-611", stem: "Budd-Chiari syndrome on Doppler ultrasound characteristically shows:", options: ["Absent or reversed flow in the hepatic veins with caudate lobe hypertrophy","Normal hepatic vein flow","Increased portal vein velocity","Dilated hepatic arteries"], correctIndex: 0, rationale: "Budd-Chiari syndrome involves hepatic vein thrombosis/obstruction. Doppler shows absent, reversed, or turbulent hepatic vein flow. The caudate lobe hypertrophies because it has independent venous drainage directly into the IVC.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-612", stem: "Portal hypertension is suggested by a portal vein diameter exceeding:", options: ["13mm","8mm","5mm","20mm"], correctIndex: 0, rationale: "Portal vein diameter >13mm suggests portal hypertension. Other signs include hepatofugal flow, splenomegaly, portosystemic collaterals (recanalized umbilical vein, splenorenal shunts), and ascites.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-613", stem: "Hepatofugal flow in the portal vein indicates:", options: ["Reversed (away from liver) portal venous flow due to severe portal hypertension","Normal antegrade portal flow","Increased hepatic arterial flow","Hepatic vein thrombosis"], correctIndex: 0, rationale: "Normal portal flow is hepatopetal (toward the liver). Hepatofugal (reversed) flow indicates severe portal hypertension where portal pressure exceeds systemic venous pressure, causing flow reversal through portosystemic collaterals.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-614", stem: "A liver transplant with hepatic artery resistive index >0.80 or <0.50 may indicate:", options: ["Transplant rejection or vascular complications","Normal postoperative findings","Biliary obstruction only","Portal vein thrombosis"], correctIndex: 0, rationale: "In liver transplants, hepatic artery RI >0.80 may suggest rejection or downstream obstruction, while RI <0.50 may indicate proximal hepatic artery stenosis (tardus-parvus). Normal transplant RI is 0.55-0.80.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-615", stem: "The TIPS (transjugular intrahepatic portosystemic shunt) is monitored sonographically by:", options: ["Measuring velocities within the shunt; normal is 90-190 cm/s with velocities <50 or >190 suggesting dysfunction","Color Doppler only without spectral analysis","B-mode measurement of shunt diameter only","Hepatic artery waveform analysis"], correctIndex: 0, rationale: "TIPS dysfunction is assessed by shunt velocities: normal 90-190 cm/s. Velocities <50 cm/s suggest stenosis/occlusion; >190 cm/s or temporal velocity change >50 cm/s suggest stenosis. Direction of portal vein flow should be into the shunt.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-616", stem: "A hepatic abscess on ultrasound typically appears as:", options: ["Complex hypoechoic or mixed echogenicity mass with irregular walls and possible internal debris or gas","Homogeneously hyperechoic well-defined mass","Simple anechoic cyst with thin walls","Calcified mass with dense posterior shadowing"], correctIndex: 0, rationale: "Hepatic abscesses appear as complex collections with variable echogenicity, irregular thick walls, internal debris, septations, or gas (dirty shadowing). Clinical correlation with fever, leukocytosis, and RUQ pain is essential.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-617", stem: "Echinococcal (hydatid) cyst of the liver characteristically shows:", options: ["Cyst with daughter cysts, floating membranes, and 'water lily sign' or 'wheel within a wheel' appearance","Simple anechoic cyst indistinguishable from other cysts","Solid hyperechoic mass","Diffuse hepatic calcification"], correctIndex: 0, rationale: "Hydatid cysts have characteristic appearances based on stage: unilocular cyst, cyst with daughter cysts, cyst with floating membranes (water lily sign), calcified cyst. Caused by Echinococcus granulosus tapeworm.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-618", stem: "The most common primary malignant liver tumor worldwide is:", options: ["Hepatocellular carcinoma","Cholangiocarcinoma","Angiosarcoma","Hepatoblastoma"], correctIndex: 0, rationale: "HCC is the most common primary liver malignancy, strongly associated with cirrhosis and hepatitis B/C. On ultrasound it is variable in echogenicity. AFP elevation supports the diagnosis. Surveillance recommended in cirrhotic patients.", difficulty: 1, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-619", stem: "A Klatskin tumor (hilar cholangiocarcinoma) causes:", options: ["Intrahepatic biliary dilation with normal-caliber common bile duct and a mass at the hepatic duct confluence","Isolated gallbladder distension","Diffuse hepatic steatosis","Portal vein aneurysm"], correctIndex: 0, rationale: "Klatskin tumor occurs at the confluence of right and left hepatic ducts. It causes intrahepatic ductal dilation without extrahepatic dilation (non-dilated CBD), creating the 'too many tubes' sign.", difficulty: 5, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-620", stem: "Choledocholithiasis on ultrasound demonstrates:", options: ["Echogenic focus within the dilated common bile duct with posterior acoustic shadowing","Thickened gallbladder wall only","Anechoic CBD without internal echoes","Hyperechoic liver parenchyma"], correctIndex: 0, rationale: "CBD stones appear as echogenic foci with shadowing within the duct. The CBD is typically dilated (>6mm, or >8mm post-cholecystectomy, or >10mm in elderly). Distal CBD stones may be obscured by duodenal gas.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-621", stem: "Normal common bile duct diameter should not exceed:", options: ["6mm (with age-related allowance of up to 1mm per decade after age 60)","2mm","15mm","10mm in all patients"], correctIndex: 0, rationale: "Normal CBD is ≤6mm. Post-cholecystectomy, up to 8mm may be normal. Some sources allow 1mm increase per decade over 60. Dilation suggests distal obstruction from stones, stricture, or mass.", difficulty: 1, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-622", stem: "Acute cholecystitis ultrasound findings include all EXCEPT:", options: ["Porcelain gallbladder with diffuse wall calcification","Positive sonographic Murphy's sign","Gallbladder wall thickening >3mm","Pericholecystic fluid"], correctIndex: 0, rationale: "Acute cholecystitis: sonographic Murphy's sign, wall thickening >3mm, pericholecystic fluid, gallstones (especially impacted in the neck). Porcelain gallbladder is chronic calcification of the wall, associated with cancer risk.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-623", stem: "The 'WES' sign (wall-echo-shadow) in the gallbladder indicates:", options: ["A gallbladder completely filled with stones showing anterior wall, stone echo, and posterior shadow","Gallbladder polyp","Adenomyomatosis","Gallbladder carcinoma"], correctIndex: 0, rationale: "WES sign occurs when the gallbladder is packed with stones: the anterior wall echo, a line of stone echoes, and clean posterior shadow. The gallbladder lumen is not visible. May mimic bowel gas on cursory scanning.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-624", stem: "Gallbladder polyps on ultrasound are characterized by:", options: ["Non-shadowing, non-mobile echogenic projections from the gallbladder wall","Mobile echogenic foci with posterior shadowing","Dependent layering debris","Anechoic structures protruding into the lumen"], correctIndex: 0, rationale: "Polyps are fixed to the wall (non-mobile), do not shadow (unlike stones), and project into the lumen. Size >10mm raises concern for malignancy and is an indication for cholecystectomy.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-625", stem: "Adenomyomatosis of the gallbladder on ultrasound shows:", options: ["Wall thickening with intramural diverticula (Rokitansky-Aschoff sinuses) producing comet-tail artifacts","Thin-walled gallbladder with clear bile","Single large stone with shadowing","Porcelain wall calcification"], correctIndex: 0, rationale: "Adenomyomatosis is a benign hyperplastic condition with mural thickening and Rokitansky-Aschoff sinuses (intramural diverticula). Cholesterol crystals within the sinuses produce characteristic comet-tail or twinkling artifacts.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-626", stem: "Mirizzi syndrome is characterized by:", options: ["A gallstone impacted in the cystic duct or gallbladder neck causing extrinsic compression of the common hepatic duct","Intrinsic CBD stricture","Gallbladder torsion","Choledochal cyst"], correctIndex: 0, rationale: "Mirizzi syndrome: a large stone in the cystic duct or Hartmann's pouch compresses the adjacent common hepatic duct, causing proximal biliary obstruction. Ultrasound shows contracted gallbladder with stone and dilated intrahepatic ducts.", difficulty: 5, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-627", stem: "Choledochal cysts are classified by the Todani classification. The most common type (Type I) involves:", options: ["Fusiform or saccular dilation of the common bile duct","Diverticulum of the CBD","Choledochocele","Intrahepatic biliary dilation only"], correctIndex: 0, rationale: "Type I choledochal cyst (80-90%) is fusiform or saccular CBD dilation. Associated with anomalous pancreaticobiliary duct junction. Risk of cholangiocarcinoma increases with age; surgical excision is recommended.", difficulty: 4, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-628", stem: "Biliary sludge on ultrasound appears as:", options: ["Low-level echoes that layer dependently within the gallbladder without posterior shadowing","Hyperechoic focus with clean posterior shadow","Wall-adherent echogenic mass","Anechoic gallbladder content"], correctIndex: 0, rationale: "Biliary sludge is a mixture of cholesterol crystals, calcium bilirubinate, and mucin. It layers dependently, moves slowly with positioning, and does not shadow. May be seen with fasting, TPN, pregnancy, or critical illness.", difficulty: 1, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-629", stem: "Gallbladder carcinoma is most commonly associated with:", options: ["Chronic cholecystitis with gallstones, porcelain gallbladder, and large polyps >10mm","Normal gallbladder without stones","Biliary sludge alone","Small polyps <5mm"], correctIndex: 0, rationale: "Gallbladder carcinoma risk factors include chronic cholecystitis, gallstones (especially large), porcelain gallbladder, polyps >10mm, and anomalous pancreaticobiliary junction. Often presents as focal or diffuse wall thickening or intraluminal mass.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-630", stem: "A courvoisier sign (palpable, distended gallbladder with painless jaundice) on ultrasound suggests:", options: ["Distal CBD obstruction due to malignancy (pancreatic head carcinoma)","Acute cholecystitis","Chronic cholecystitis with stones","Hepatic cirrhosis"], correctIndex: 0, rationale: "Courvoisier's law: painless jaundice with a palpable gallbladder is unlikely due to gallstones (which cause chronic fibrosis). It suggests malignant distal CBD obstruction, most commonly pancreatic head carcinoma.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-631", stem: "Emphysematous cholecystitis is a surgical emergency characterized by:", options: ["Gas within the gallbladder wall producing dirty shadowing and reverberation artifacts","Simple gallstones with clean shadowing","Gallbladder polyps","Normal gallbladder wall with sludge"], correctIndex: 0, rationale: "Emphysematous cholecystitis involves gas-forming organisms (Clostridium, E. coli) causing gas within the gallbladder wall and lumen. Ultrasound shows reverberation/dirty shadowing from intramural gas. High mortality; requires emergent cholecystectomy.", difficulty: 4, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-632", stem: "A pancreatic head mass causing double duct sign (dilated CBD and pancreatic duct) most likely represents:", options: ["Pancreatic adenocarcinoma","Acute pancreatitis","Pancreatic pseudocyst","Chronic pancreatitis without mass"], correctIndex: 0, rationale: "The double duct sign (simultaneous dilation of CBD and pancreatic duct) is highly suspicious for pancreatic head carcinoma compressing both ducts. Pancreatic adenocarcinoma is typically hypoechoic relative to normal pancreas.", difficulty: 3, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-633", stem: "A pancreatic pseudocyst on ultrasound appears as:", options: ["Well-defined anechoic or hypoechoic collection near or within the pancreas, often following pancreatitis","Solid hyperechoic mass","Calcified mass with dense shadowing","Normal pancreatic tissue"], correctIndex: 0, rationale: "Pseudocysts are encapsulated collections of pancreatic secretions without an epithelial lining, arising 4-6 weeks after acute pancreatitis. They appear as well-defined, round/oval, anechoic/hypoechoic collections.", difficulty: 2, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-634", stem: "Chronic pancreatitis on ultrasound demonstrates:", options: ["Heterogeneous, hyperechoic pancreas with calcifications, ductal dilation and irregularity","Enlarged hypoechoic homogeneous pancreas","Normal echogenicity with smooth borders","Anechoic pancreatic cyst only"], correctIndex: 0, rationale: "Chronic pancreatitis shows parenchymal calcifications with shadowing, ductal dilation (>3mm) with irregularity, parenchymal atrophy, and heterogeneous echotexture. Alcohol abuse is the most common cause.", difficulty: 2, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-635", stem: "Intraductal papillary mucinous neoplasm (IPMN) of the pancreas is characterized by:", options: ["Cystic dilation of the main pancreatic duct or branch ducts with possible mural nodules","Solid hypoechoic mass replacing the entire pancreas","Diffuse pancreatic calcification","Peripancreatic lymphadenopathy only"], correctIndex: 0, rationale: "IPMNs produce mucin causing ductal dilation. Main duct type (>5mm duct) has higher malignant potential. Branch duct type appears as cystic lesion communicating with the duct. Mural nodules and main duct involvement increase cancer risk.", difficulty: 4, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-636", stem: "A serous cystadenoma of the pancreas typically appears as:", options: ["Microcystic lesion with multiple small cysts giving a honeycomb or sponge-like appearance with central stellate scar","Single large unilocular cyst","Solid mass without cystic components","Calcified mass with shadowing"], correctIndex: 0, rationale: "Serous cystadenomas are benign tumors with multiple small cysts (<2cm each) creating a honeycomb pattern. Central sunburst calcification may be present. Most common in elderly women. Rarely malignant.", difficulty: 4, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-637", stem: "A mucinous cystic neoplasm of the pancreas differs from serous cystadenoma by:", options: ["Having fewer, larger cystic spaces (macrocystic), peripheral calcification, and higher malignant potential","Having multiple tiny cysts in a honeycomb pattern","Being always benign with no malignant potential","Occurring predominantly in elderly men"], correctIndex: 0, rationale: "Mucinous cystic neoplasms are macrocystic (few large cysts), occur almost exclusively in women (body/tail), have peripheral eggshell calcification, and carry significant malignant potential. Surgical resection is recommended.", difficulty: 4, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-638", stem: "A pancreatic neuroendocrine tumor (e.g., insulinoma) on ultrasound typically appears as:", options: ["Well-defined hypoechoic hypervascular solid mass","Anechoic cyst with thin wall","Hyperechoic mass with shadowing","Diffuse pancreatic calcification"], correctIndex: 0, rationale: "Pancreatic neuroendocrine tumors are typically well-defined, hypoechoic, and hypervascular on Doppler. Insulinomas are the most common functional type, presenting with hypoglycemia. Most are small (<2cm) and benign.", difficulty: 3, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-639", stem: "Autoimmune pancreatitis on ultrasound may mimic pancreatic carcinoma by showing:", options: ["Diffuse or focal pancreatic enlargement with hypoechoic parenchyma (sausage-shaped pancreas)","Multiple calcifications with ductal dilation","Normal-appearing pancreas","Peripancreatic pseudocyst"], correctIndex: 0, rationale: "Autoimmune pancreatitis causes diffuse ('sausage-shaped') or focal pancreatic enlargement with loss of lobular contour. It can mimic carcinoma. Elevated IgG4, response to steroids, and capsule-like rim help differentiate.", difficulty: 5, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-640", stem: "The normal pancreatic duct (Wirsung) diameter should not exceed:", options: ["2-3mm in the body","6mm","10mm","1cm in the head"], correctIndex: 0, rationale: "Normal pancreatic duct measures ≤2mm in the body and ≤3mm in the head. Dilation beyond these values suggests downstream obstruction (stone, stricture, mass) or chronic pancreatitis.", difficulty: 1, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-641", stem: "Splenomegaly on ultrasound is defined as a spleen length exceeding:", options: ["12-13cm","8cm","5cm","18cm"], correctIndex: 0, rationale: "Splenomegaly is splenic length >12-13cm. Causes include portal hypertension, hematologic disorders (lymphoma, leukemia, sickle cell), infections (mononucleosis, malaria), and storage diseases (Gaucher).", difficulty: 1, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-642", stem: "A hypoechoic splenic lesion in a patient with lymphoma most likely represents:", options: ["Lymphomatous infiltration of the spleen","Splenic hemangioma","Simple splenic cyst","Splenic calcification"], correctIndex: 0, rationale: "Lymphoma is the most common malignancy involving the spleen. It can appear as diffuse splenomegaly with normal echotexture, focal hypoechoic lesions, or miliary pattern. Hypoechoic focal lesions in lymphoma patients suggest splenic involvement.", difficulty: 2, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-643", stem: "Splenic infarction on ultrasound appears as:", options: ["Wedge-shaped, peripheral, hypoechoic area that does not demonstrate flow on color Doppler","Round hyperechoic central lesion","Diffuse increased echogenicity","Cystic lesion with septations"], correctIndex: 0, rationale: "Splenic infarcts are typically wedge-shaped with the apex pointing toward the hilum and base toward the capsule. Initially hypoechoic, they become hyperechoic/calcified over time. Causes include embolism, sickle cell, and myeloproliferative disorders.", difficulty: 3, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-644", stem: "An accessory spleen (splenunculus) is found in approximately what percentage of the population?", options: ["10-30%","1-2%","50-60%","Less than 0.1%"], correctIndex: 0, rationale: "Accessory spleens occur in 10-30% of the population, most commonly at the splenic hilum. They appear as small (1-2cm), round, homogeneous structures with identical echogenicity to the spleen.", difficulty: 2, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-645", stem: "Splenic artery aneurysm is significant because:", options: ["It is the most common visceral artery aneurysm with risk of rupture, especially during pregnancy","It always requires emergent surgery","It only occurs in elderly men","It is always asymptomatic and benign"], correctIndex: 0, rationale: "Splenic artery aneurysm is the most common visceral artery aneurysm. Rupture risk increases with size >2cm, pregnancy, and portal hypertension. On ultrasound, it appears as a cystic structure at the splenic hilum with arterial Doppler flow.", difficulty: 3, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-646", stem: "A wandering spleen on ultrasound is identified by:", options: ["Absence of the spleen in the left upper quadrant with an ectopic mass of splenic tissue elsewhere in the abdomen","Enlarged spleen in the normal position","Multiple splenic lesions","Calcified splenic mass"], correctIndex: 0, rationale: "Wandering spleen results from laxity or absence of splenic ligaments, allowing the spleen to migrate. Risk of torsion and infarction. The empty splenic fossa and identification of splenic tissue ectopically confirms the diagnosis.", difficulty: 4, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-647", stem: "Splenic abscess on ultrasound appears as:", options: ["Complex hypoechoic or mixed echogenicity lesion with possible internal debris and gas","Simple anechoic cyst with thin wall","Solid hyperechoic mass","Calcified granuloma"], correctIndex: 0, rationale: "Splenic abscesses are complex fluid collections from hematogenous spread, endocarditis, or immunosuppression. They appear as hypoechoic/complex lesions with internal debris, septations, or gas. May show peripheral vascularity.", difficulty: 3, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-648", stem: "Gamna-Gandy bodies in the spleen are:", options: ["Small echogenic foci representing iron and calcium deposits from prior hemorrhage, seen in portal hypertension","Splenic metastases","Lymphoma deposits","Normal splenic variants"], correctIndex: 0, rationale: "Gamna-Gandy bodies (siderotic nodules) are small foci of hemosiderin and calcium from old microhemorrhages. Seen as tiny echogenic foci in patients with portal hypertension, sickle cell disease, or hemolytic anemias.", difficulty: 5, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-649", stem: "Splenic hemangioma on ultrasound typically appears as:", options: ["Well-defined echogenic mass, similar to hepatic hemangiomas","Completely anechoic cyst","Diffuse hypoechoic infiltration","Complex mass with internal flow reversal"], correctIndex: 0, rationale: "Splenic hemangiomas are the most common benign splenic neoplasm. They appear as well-defined, homogeneously echogenic lesions similar to hepatic hemangiomas. Larger lesions may be heterogeneous with cystic or calcified areas.", difficulty: 3, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-650", stem: "Polysplenia syndrome is associated with:", options: ["Multiple small spleens on the left side, bilateral left-sidedness, and cardiac anomalies","A single enlarged spleen","Right-sided stomach","Normal splenic anatomy with renal anomalies"], correctIndex: 0, rationale: "Polysplenia (left isomerism) features multiple small spleens, bilateral left-sidedness (bilobed lungs), interrupted IVC with azygos continuation, and congenital heart defects. It is a heterotaxy syndrome.", difficulty: 5, category: "Abdominal Sonography", topic: "Splenic Abnormalities" },
  { id: "sono-651", stem: "A simple renal cyst on ultrasound must meet which criteria (Bosniak I)?", options: ["Anechoic, well-defined thin wall, posterior acoustic enhancement, no internal echoes or septations","Thick septations with calcification","Solid components with vascularity","Irregular wall thickening"], correctIndex: 0, rationale: "Bosniak I (simple) cysts are anechoic, round/oval, imperceptible thin smooth wall, posterior enhancement, no septations, calcifications, or solid components. They are benign and require no follow-up.", difficulty: 1, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-652", stem: "A Bosniak II renal cyst may contain:", options: ["Thin septations, fine calcification, or hyperdense content <3cm without enhancement","Thick enhancing septations >2mm","Solid enhancing nodular component","Irregular wall thickening with vascularity"], correctIndex: 0, rationale: "Bosniak II cysts have thin (<1mm) septations, fine calcification in wall or septa, hyperdense cysts <3cm (high attenuation on CT). They are benign with <5% malignancy risk and generally require no follow-up.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-653", stem: "A Bosniak III renal cyst is characterized by:", options: ["Thick irregular walls or septations, measurable enhancement, indeterminate for malignancy (~50% cancer risk)","Simple anechoic cyst","Thin hairline septation","Purely solid mass without cystic component"], correctIndex: 0, rationale: "Bosniak III lesions have thickened irregular walls or septations with measurable enhancement. Approximately 50% are malignant. Surgical excision or close surveillance with imaging is recommended.", difficulty: 4, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-654", stem: "Angiomyolipoma (AML) of the kidney on ultrasound appears as:", options: ["Well-defined, markedly hyperechoic mass without posterior shadowing due to fat content","Hypoechoic mass with calcification","Complex cystic lesion","Anechoic renal lesion"], correctIndex: 0, rationale: "AMLs contain fat, smooth muscle, and blood vessels. Fat content makes them markedly hyperechoic on ultrasound. Small AMLs (<4cm) are usually monitored; larger ones risk hemorrhage. Associated with tuberous sclerosis.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-655", stem: "Renal cell carcinoma (RCC) on ultrasound most commonly appears as:", options: ["Solid mass with variable echogenicity (hypo-, iso-, or hyperechoic) with internal vascularity on Doppler","Always anechoic cystic lesion","Uniformly hyperechoic mass indistinguishable from AML","Calcified mass without blood flow"], correctIndex: 0, rationale: "RCC is the most common malignant renal tumor in adults. It has variable echogenicity and may be iso-, hypo-, or hyperechoic. Color Doppler shows internal vascularity. May invade the renal vein and IVC.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-656", stem: "Renal cell carcinoma extending into the renal vein and IVC is called:", options: ["Tumor thrombus, which must be differentiated from bland thrombus using Doppler to detect arterial flow within the thrombus","Renal infarction","Budd-Chiari syndrome","Nutcracker syndrome"], correctIndex: 0, rationale: "RCC can extend as tumor thrombus into the renal vein and IVC in up to 10% of cases. Doppler shows arterial flow within tumor thrombus (unlike bland thrombus). This finding is critical for surgical planning.", difficulty: 4, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-657", stem: "Autosomal dominant polycystic kidney disease (ADPKD) on ultrasound shows:", options: ["Bilaterally enlarged kidneys with multiple cysts of varying sizes replacing normal parenchyma","Single cortical cyst in one kidney","Small echogenic kidneys","Normal-appearing kidneys with ureteral dilation"], correctIndex: 0, rationale: "ADPKD shows bilaterally enlarged kidneys with innumerable cysts of varying sizes. Hepatic cysts are common. Diagnosis requires age-based criteria (number of cysts). Complications include hemorrhagic cysts, stones, and hypertension.", difficulty: 1, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-658", stem: "A multilocular cystic nephroma on ultrasound appears as:", options: ["Well-defined multiloculated cystic renal mass with thin septa and no solid components","Solid hyperechoic mass","Simple cortical cyst","Staghorn calculus"], correctIndex: 0, rationale: "Multilocular cystic nephroma is a benign tumor with multiple non-communicating cysts separated by thin septa. It occurs in two peaks: boys <2 years and women >40 years. Differentiation from cystic RCC may require surgery.", difficulty: 4, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-659", stem: "Transitional cell carcinoma (TCC/urothelial carcinoma) of the kidney on ultrasound appears as:", options: ["Hypoechoic soft tissue mass within the renal pelvis/collecting system causing hydronephrosis","Peripheral cortical hyperechoic mass","Simple renal cyst","Multiple small calcifications without mass"], correctIndex: 0, rationale: "TCC of the renal pelvis appears as a hypoechoic mass within the collecting system, often causing obstruction and hydronephrosis. It may show vascularity on Doppler. Associated with smoking and chemical exposure.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-660", stem: "Oncocytoma of the kidney on ultrasound:", options: ["Cannot be reliably differentiated from RCC sonographically; a central stellate scar may be present","Always appears as an anechoic cyst","Shows pathognomonic features distinguishing it from RCC","Is always calcified with shadowing"], correctIndex: 0, rationale: "Oncocytoma is a benign solid renal tumor that may show a central scar but cannot be reliably distinguished from RCC on imaging alone. Biopsy or surgical excision is typically required for definitive diagnosis.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-661", stem: "A junctional parenchymal defect of the kidney should not be confused with a mass because:", options: ["It is a normal developmental variant representing the junction of fetal renal lobules, appearing as a hyperechoic triangular focus","It shows internal vascularity on Doppler","It grows on serial imaging","It causes hydronephrosis"], correctIndex: 0, rationale: "Junctional parenchymal defect is a normal variant from incomplete fusion of fetal renal lobules. It appears as a triangular echogenic area at the junction of upper and lower poles, typically anteromedially. No follow-up needed.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-662", stem: "A column of Bertin (hypertrophied column) on ultrasound appears as:", options: ["Normal renal cortical tissue extending into the renal sinus between calyces, isoechoic to cortex","Hyperechoic mass within the collecting system","Anechoic cyst in the renal hilum","Calcified mass at the corticomedullary junction"], correctIndex: 0, rationale: "A column of Bertin is a normal variant of hypertrophied cortical tissue projecting into the sinus between calyces. It is isoechoic to cortex, shows normal vascularity, and should not be mistaken for a mass.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-663", stem: "A dromedary hump of the kidney is:", options: ["A normal variant of focal cortical bulge on the lateral left kidney caused by the impression of the spleen","A renal mass requiring biopsy","A sign of renal vein thrombosis","An indicator of chronic kidney disease"], correctIndex: 0, rationale: "A dromedary hump is a focal cortical bulge on the lateral aspect of the left kidney from splenic impression. It is isoechoic to normal cortex and shows normal vascularity, distinguishing it from a mass.", difficulty: 1, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-664", stem: "Nephrocalcinosis on ultrasound is characterized by:", options: ["Echogenic renal pyramids (medullary nephrocalcinosis) from calcium deposits within the medulla","Cortical thinning only","Enlarged kidneys with multiple cysts","Hypoechoic renal pyramids"], correctIndex: 0, rationale: "Medullary nephrocalcinosis shows echogenic renal pyramids with or without shadowing. Causes include hyperparathyroidism, medullary sponge kidney, renal tubular acidosis, and hypercalcemia.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-665", stem: "Xanthogranulomatous pyelonephritis (XGP) on ultrasound shows:", options: ["Enlarged non-functioning kidney with central echogenic staghorn calculus and multiple hypoechoic areas representing dilated calyces filled with debris","Normal kidney with simple cyst","Small echogenic kidney","Bilateral hydronephrosis"], correctIndex: 0, rationale: "XGP is a chronic destructive granulomatous infection often associated with staghorn calculi and Proteus/E. coli infection. The kidney is enlarged and non-functional with multiple hypoechoic areas (pus-filled calyces). May mimic renal mass.", difficulty: 5, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-666", stem: "Wilms tumor (nephroblastoma) on ultrasound in a child appears as:", options: ["Large, well-defined solid mass arising from the kidney with heterogeneous echotexture","Small cortical cyst","Bilateral hyperechoic kidneys","Medullary calcifications only"], correctIndex: 0, rationale: "Wilms tumor is the most common renal malignancy in children (ages 1-5). It appears as a large, solid, well-circumscribed intrarenal mass with heterogeneous echotexture. May contain cystic or hemorrhagic areas.", difficulty: 2, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-667", stem: "Hepatic cirrhosis on ultrasound demonstrates:", options: ["Coarsened heterogeneous echotexture, nodular liver surface, caudate lobe enlargement, and signs of portal hypertension","Smooth liver surface with normal echogenicity","Diffusely decreased echogenicity","Multiple simple cysts"], correctIndex: 0, rationale: "Cirrhosis shows surface nodularity, heterogeneous coarsened parenchyma, right lobe atrophy with caudate/left lobe hypertrophy, and portal hypertension signs (splenomegaly, ascites, varices, hepatofugal flow).", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-668", stem: "A hepatic adenoma is most commonly associated with:", options: ["Oral contraceptive use and anabolic steroid use in young women","Chronic hepatitis C","Alcohol abuse","Portal hypertension"], correctIndex: 0, rationale: "Hepatic adenomas are benign tumors strongly associated with OCP use and anabolic steroids. They are well-defined, variable echogenicity (often hyperechoic due to fat/glycogen), with risk of hemorrhage and rare malignant transformation.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-669", stem: "Periportal cuffing on ultrasound refers to:", options: ["Hypoechoic tracking along the portal triads suggesting edema, inflammation, or lymphatic congestion","Echogenic portal vein walls","Dilated intrahepatic bile ducts","Hepatic vein thrombus"], correctIndex: 0, rationale: "Periportal cuffing appears as hypoechoic halos around portal tracts, representing edema from hepatitis, heart failure, transplant rejection, or lymphatic obstruction. It creates a 'starry sky' appearance when combined with bright portal walls.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-670", stem: "The 'starry sky' liver pattern on ultrasound is seen in:", options: ["Acute hepatitis, where diffuse hypoechoic edematous parenchyma contrasts with bright portal triad walls","Fatty liver","Hepatic cirrhosis","Normal liver"], correctIndex: 0, rationale: "Starry sky pattern occurs in acute hepatitis: diffuse parenchymal edema causes decreased echogenicity while portal triad walls remain bright, creating a contrasting pattern. Also seen in toxic hepatitis and leukemic infiltration.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-671", stem: "Hepatic candidiasis (microabscesses) on ultrasound typically shows:", options: ["Multiple small hypoechoic lesions ('wheel within a wheel' or 'bull's-eye') scattered throughout the liver in immunocompromised patients","Single large hyperechoic mass","Diffuse calcification","Normal liver echotexture"], correctIndex: 0, rationale: "Hepatic candidiasis occurs in immunocompromised patients (neutropenic recovery). Multiple small (5-20mm) hypoechoic lesions with possible target/bull's-eye appearance are scattered throughout the liver and often the spleen.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-672", stem: "Focal fatty infiltration of the liver appears as:", options: ["Geographic hyperechoic area without mass effect on adjacent vessels, no alteration of hepatic architecture","Round hypoechoic mass with Doppler flow","Cystic lesion with septations","Calcified mass with shadowing"], correctIndex: 0, rationale: "Focal fatty infiltration is a geographic area of increased echogenicity that does not displace vessels or alter hepatic architecture. Common locations include adjacent to the gallbladder fossa and falciform ligament. No mass effect distinguishes it from a true mass.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-673", stem: "Focal fatty sparing in a steatotic liver appears as:", options: ["Hypoechoic area against a diffusely echogenic background, typically near the gallbladder fossa or porta hepatis","Hyperechoic mass requiring biopsy","Calcified nodule","Complex cystic mass"], correctIndex: 0, rationale: "Focal fatty sparing is normal liver tissue that appears relatively hypoechoic compared to the surrounding fatty liver. Typical locations include gallbladder fossa and segment IV near the porta hepatis. No mass effect helps differentiation.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-674", stem: "The hepatic veins drain into the:", options: ["Inferior vena cava","Portal vein","Hepatic artery","Superior mesenteric vein"], correctIndex: 0, rationale: "The three main hepatic veins (right, middle, left) drain directly into the IVC at its intrahepatic/suprahepatic portion. Hepatic vein Doppler normally shows triphasic waveform reflecting cardiac activity.", difficulty: 1, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-675", stem: "Normal hepatic vein Doppler waveform is:", options: ["Triphasic with flow toward the IVC reflecting right atrial pressure changes","Continuous monophasic","Pulsatile with flow away from the IVC","Biphasic with equal forward and reverse components"], correctIndex: 0, rationale: "Normal hepatic vein waveform is triphasic: two antegrade components (systolic and diastolic filling) and one retrograde component (atrial contraction). Loss of phasicity suggests hepatic parenchymal disease.", difficulty: 2, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-676", stem: "Loss of hepatic vein triphasic waveform (monophasic or flat) suggests:", options: ["Hepatic parenchymal disease such as cirrhosis or fatty infiltration","Normal variant","Hepatic artery stenosis","Renal artery stenosis"], correctIndex: 0, rationale: "Loss of triphasic hepatic vein pulsatility occurs with increased hepatic parenchymal resistance from cirrhosis, fatty liver, or hepatic congestion. The waveform becomes monophasic or flat (dampened).", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-677", stem: "A Riedel lobe of the liver is:", options: ["A normal anatomic variant of an elongated right hepatic lobe extending below the costal margin","A pathologic mass requiring biopsy","An accessory liver lobe with independent blood supply","A sign of hepatomegaly"], correctIndex: 0, rationale: "A Riedel lobe is a tongue-like extension of the right hepatic lobe below the costal margin, most common in women. It is a normal variant, not a sign of hepatomegaly, and should not be confused with pathology.", difficulty: 1, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-678", stem: "Acute cholangitis typically presents on ultrasound with:", options: ["Dilated bile ducts with echogenic debris (pus) and clinical Charcot's triad (fever, jaundice, RUQ pain)","Normal bile ducts","Contracted gallbladder","Hepatic vein thrombosis"], correctIndex: 0, rationale: "Acute cholangitis: biliary obstruction (usually from stones) with bacterial infection causing pus in the ducts. Ultrasound shows dilated ducts with echogenic material. Charcot's triad or Reynolds' pentad (plus hypotension and altered mental status).", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-679", stem: "Primary sclerosing cholangitis (PSC) on ultrasound may show:", options: ["Irregular thickening of bile duct walls with alternating stenoses and dilations ('beaded' appearance)","Normal bile ducts in all cases","Gallbladder polyps only","Simple choledochal cyst"], correctIndex: 0, rationale: "PSC causes progressive inflammation and fibrosis of intrahepatic and extrahepatic bile ducts. Ultrasound may show duct wall thickening, irregular dilation, and the beaded pattern. Associated with inflammatory bowel disease (especially UC).", difficulty: 4, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-680", stem: "A Caroli disease on ultrasound shows:", options: ["Saccular dilation of intrahepatic bile ducts with the 'central dot sign' representing portal vein radicles surrounded by dilated ducts","Diffuse hepatic steatosis","Simple hepatic cysts","Normal biliary anatomy"], correctIndex: 0, rationale: "Caroli disease is congenital saccular dilation of intrahepatic bile ducts. The central dot sign (portal vein radicle within dilated duct) is pathognomonic. Associated with congenital hepatic fibrosis, choledochal cysts, and cholangiocarcinoma risk.", difficulty: 5, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-681", stem: "Pneumobilia (air in the bile ducts) on ultrasound appears as:", options: ["Bright linear echoes within the bile ducts with dirty posterior shadowing, located centrally in the liver","Shadowing from gallstones","Smooth anechoic tubular structures","Echogenic liver parenchyma"], correctIndex: 0, rationale: "Pneumobilia shows as bright echoes with reverberation/dirty shadowing in a non-dependent distribution within bile ducts (central). Causes include post-ERCP/sphincterotomy, biliary-enteric anastomosis, and incompetent sphincter of Oddi.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-682", stem: "The difference between pneumobilia and portal venous gas on ultrasound is:", options: ["Pneumobilia is central (follows bile ducts) while portal venous gas is peripheral (flows to liver periphery)","They are identical in location","Pneumobilia is always peripheral","Portal venous gas is always central"], correctIndex: 0, rationale: "Pneumobilia collects centrally in bile ducts (non-dependent). Portal venous gas flows peripherally with portal blood. Portal venous gas is more ominous, associated with mesenteric ischemia, necrotizing enterocolitis, or bowel necrosis.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-683", stem: "Acute acalculous cholecystitis occurs most frequently in:", options: ["Critically ill, hospitalized, or immunocompromised patients","Healthy young adults","Children with biliary sludge","Elderly patients with gallstones"], correctIndex: 0, rationale: "Acalculous cholecystitis (5-10% of acute cholecystitis) occurs in critically ill patients (ICU, TPN, burns, sepsis, AIDS). Gallbladder ischemia and bile stasis cause inflammation without stones. Wall thickening, distension, pericholecystic fluid without stones.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-684", stem: "A porcelain gallbladder on ultrasound appears as:", options: ["Curvilinear echogenic focus in the gallbladder fossa with dense posterior acoustic shadowing from wall calcification","Normal thin-walled gallbladder","Gallbladder with sludge","Distended gallbladder with polyps"], correctIndex: 0, rationale: "Porcelain gallbladder is calcification of the gallbladder wall. On ultrasound it shows a curvilinear hyperechoic anterior wall with dense posterior shadowing. Associated with increased risk of gallbladder carcinoma; cholecystectomy is recommended.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-685", stem: "Hepatic peliosis on ultrasound appears as:", options: ["Multiple small hypoechoic or anechoic blood-filled spaces scattered throughout the liver","Diffuse hyperechoic liver","Single large calcified mass","Normal liver echotexture"], correctIndex: 0, rationale: "Peliosis hepatis is characterized by blood-filled cavities within the liver. On ultrasound, multiple small hypoechoic or cystic lesions are seen. Associated with anabolic steroids, oral contraceptives, and immunosuppressive therapy.", difficulty: 5, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-686", stem: "A liver with a 'nutmeg' pattern on pathology corresponds to which ultrasound finding?", options: ["Diffuse heterogeneous echotexture with dilated hepatic veins and IVC from hepatic congestion","Homogeneously hyperechoic liver","Multiple calcified nodules","Small shrunken liver with nodular surface"], correctIndex: 0, rationale: "Nutmeg liver results from chronic hepatic congestion (right heart failure). Ultrasound shows dilated hepatic veins and IVC, heterogeneous parenchyma, hepatomegaly, and possible pulsatile portal vein flow from transmitted cardiac pressures.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-687", stem: "Hepatic epithelioid hemangioendothelioma on ultrasound appears as:", options: ["Multiple peripheral hypoechoic or target-appearing nodules that may coalesce, with capsular retraction","Single central hyperechoic mass","Simple cyst with thin septation","Diffuse fatty infiltration"], correctIndex: 0, rationale: "Hepatic epithelioid hemangioendothelioma is a rare vascular malignancy. It presents as multiple peripheral nodules that coalesce, cause capsular retraction, and may calcify. It has a variable prognosis, better than angiosarcoma.", difficulty: 5, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-688", stem: "The caudate lobe to right lobe ratio in cirrhosis is significant when:", options: ["Greater than 0.65, suggesting caudate lobe hypertrophy characteristic of cirrhosis","Less than 0.30","Equal to 1.0","Less than 0.10"], correctIndex: 0, rationale: "Caudate lobe-to-right lobe ratio >0.65 is specific for cirrhosis. The caudate lobe hypertrophies because of its independent venous drainage directly into the IVC, while the right lobe atrophies due to cirrhotic changes.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-689", stem: "Schistosomiasis (periportal fibrosis) of the liver on ultrasound shows:", options: ["Echogenic thickening along portal triads creating a 'turtle back' or 'clay pipe stem' pattern","Diffuse hypoechoic liver","Multiple simple cysts","Normal hepatic echotexture"], correctIndex: 0, rationale: "Hepatic schistosomiasis causes periportal fibrosis with echogenic thickening around portal triads (turtle back/pipestem pattern). Often seen with portal hypertension, splenomegaly, and portosystemic collaterals in endemic regions.", difficulty: 5, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-690", stem: "A hepatic angiosarcoma is associated with:", options: ["Exposure to thorotrast, vinyl chloride, arsenic, or anabolic steroids","Oral contraceptive use alone","Hepatitis B infection","Alcohol consumption"], correctIndex: 0, rationale: "Hepatic angiosarcoma is a rare aggressive vascular malignancy associated with thorotrast (radioactive contrast), vinyl chloride, arsenic, and anabolic steroids. It appears as heterogeneous masses that may be multifocal with hemorrhage.", difficulty: 5, category: "Abdominal Sonography", topic: "Liver Pathology" },
  { id: "sono-691", stem: "The sonographic Murphy's sign is considered positive when:", options: ["Maximum tenderness is elicited when the transducer directly compresses the gallbladder","The patient reports pain anywhere in the abdomen during scanning","There is no tenderness with transducer pressure","The gallbladder wall is thickened"], correctIndex: 0, rationale: "Sonographic Murphy's sign is maximal tenderness when the transducer is pressed directly over the gallbladder. It is the most sensitive sign for acute cholecystitis (>90%) when combined with gallstones. Absent in gangrenous cholecystitis.", difficulty: 1, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-692", stem: "Gangrenous cholecystitis should be suspected when:", options: ["The patient has severe symptoms but absent sonographic Murphy's sign with asymmetric wall thickening, intraluminal membranes, and pericholecystic fluid","The gallbladder appears completely normal","Only gallstones are present without wall changes","The patient reports mild intermittent pain"], correctIndex: 0, rationale: "Gangrenous cholecystitis features necrosis of the gallbladder wall. Absent Murphy's sign (denervation), asymmetric wall thickening, intraluminal membranes (sloughed mucosa), gas, and pericholecystic abscess are typical findings.", difficulty: 4, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-693", stem: "The common bile duct is measured on ultrasound:", options: ["From inner wall to inner wall at its widest point, anterior to the portal vein","From outer wall to outer wall","At the ampulla of Vater only","At the cystic duct junction exclusively"], correctIndex: 0, rationale: "CBD is measured inner wall to inner wall at its widest visible point. It runs anterior to the portal vein in the porta hepatis. Normal ≤6mm; post-cholecystectomy ≤8mm. Always measure perpendicular to the duct.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-694", stem: "The parallel channel sign ('shotgun sign') in the liver indicates:", options: ["Dilated intrahepatic bile ducts running parallel to the portal vein branches, indicating biliary obstruction","Normal hepatic anatomy","Hepatic artery aneurysm","Portal vein thrombosis"], correctIndex: 0, rationale: "The parallel channel (shotgun/double barrel) sign shows dilated intrahepatic bile ducts alongside portal vein branches. Normally bile ducts are too small to visualize. This sign indicates intrahepatic biliary dilation from downstream obstruction.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Disease" },
  { id: "sono-695", stem: "A solid pancreatic body mass causing splenic vein thrombosis and left-sided portal hypertension suggests:", options: ["Pancreatic carcinoma or mass compressing the splenic vein","Splenic artery aneurysm","Simple pancreatic cyst","Chronic liver disease"], correctIndex: 0, rationale: "Pancreatic body/tail masses can compress or invade the splenic vein, causing thrombosis and sinistral (left-sided) portal hypertension. This leads to isolated gastric varices without esophageal varices, splenomegaly, and possible GI bleeding.", difficulty: 4, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-696", stem: "Groove pancreatitis occurs in:", options: ["The groove between the pancreatic head, duodenum, and common bile duct, mimicking pancreatic head carcinoma","The pancreatic tail only","The splenic hilum","The liver parenchyma"], correctIndex: 0, rationale: "Groove pancreatitis affects the anatomic groove between the pancreatic head, duodenum, and CBD. It can mimic pancreatic head carcinoma. History of alcohol abuse, cystic changes in the duodenal wall, and response to conservative management help differentiate.", difficulty: 5, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-697", stem: "Pancreas divisum may be suspected on ultrasound when:", options: ["The dorsal pancreatic duct is dilated without dilation of the ventral duct in recurrent pancreatitis","Both ducts are equally dilated","The pancreas is absent","Diffuse calcification is present"], correctIndex: 0, rationale: "Pancreas divisum is a congenital variant where dorsal and ventral pancreatic ducts fail to fuse. The dorsal duct drains most of the pancreas through the minor papilla, which may cause recurrent pancreatitis if drainage is inadequate.", difficulty: 4, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-698", stem: "A solid and papillary epithelial neoplasm (SPEN/Frantz tumor) of the pancreas typically occurs in:", options: ["Young women, appearing as a large well-encapsulated mass with mixed solid and cystic components","Elderly men with calcification","Children with diffuse pancreatic enlargement","Postmenopausal women with ductal dilation"], correctIndex: 0, rationale: "SPEN (Frantz tumor) is a low-grade malignant tumor occurring predominantly in young women (20s-30s). It is large, well-encapsulated, with mixed solid and cystic/hemorrhagic components. Prognosis is excellent after surgical resection.", difficulty: 4, category: "Abdominal Sonography", topic: "Pancreatic Lesions" },
  { id: "sono-699", stem: "Perinephric abscess on ultrasound appears as:", options: ["Complex fluid collection surrounding the kidney within Gerota's fascia, often with internal debris and septations","Simple anechoic renal cyst","Normal perinephric fat","Hyperechoic mass within the renal pelvis"], correctIndex: 0, rationale: "Perinephric abscess is a purulent collection between the renal capsule and Gerota's fascia, usually complicating pyelonephritis or renal abscess rupture. It appears as a complex hypoechoic collection with debris, septations, or gas.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-700", stem: "Renal lymphoma on ultrasound most commonly appears as:", options: ["Multiple bilateral hypoechoic renal masses or diffuse renal enlargement with homogeneous hypoechoic infiltration","Single hyperechoic mass","Multiple calcified masses","Bilateral renal cysts"], correctIndex: 0, rationale: "Renal lymphoma typically presents as multiple bilateral hypoechoic masses or diffuse infiltration causing nephromegaly. It can also appear as a solitary mass, perirenal mass, or retroperitoneal mass encasing the kidney.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-701", stem: "Medullary sponge kidney on ultrasound shows:", options: ["Echogenic renal pyramids with possible small cystic spaces in the medulla representing dilated collecting tubules","Normal renal echogenicity","Large cortical cysts","Shrunken kidney with thin cortex"], correctIndex: 0, rationale: "Medullary sponge kidney is characterized by dilated collecting tubules in the medulla that may contain calcifications. Ultrasound shows echogenic pyramids (medullary nephrocalcinosis). Often bilateral and associated with recurrent UTIs and stones.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-702", stem: "Renal artery stenosis causing renovascular hypertension shows which indirect Doppler finding?", options: ["Tardus-parvus waveform in intrarenal arteries (delayed systolic upstroke with rounded peak)","Increased resistive index >0.90","Normal sharp systolic peak","Absent diastolic flow"], correctIndex: 0, rationale: "Tardus-parvus is an indirect sign of proximal renal artery stenosis: slow systolic upstroke (tardus) and diminished peak (parvus) in segmental and interlobar arteries. Acceleration time >70ms and acceleration index <3.0 m/s² are abnormal.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-703", stem: "A parapelvic cyst differs from hydronephrosis on ultrasound because:", options: ["Parapelvic cysts do not connect with each other and are not contiguous with the renal pelvis, while hydronephrosis shows communicating fluid-filled collecting system","They are identical in appearance","Parapelvic cysts always calcify","Hydronephrosis never shows fluid in the renal sinus"], correctIndex: 0, rationale: "Parapelvic cysts are peripelvic lymphatic cysts in the renal sinus that mimic hydronephrosis. Key distinction: parapelvic cysts do not communicate and show no connection to the renal pelvis/calyces, unlike the continuous fluid of hydronephrosis.", difficulty: 3, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-704", stem: "Acute renal vein thrombosis on ultrasound shows:", options: ["Enlarged kidney with loss of corticomedullary differentiation, echogenic thrombus in the renal vein, and absent venous Doppler flow","Small hyperechoic kidney","Normal kidney with simple cyst","Dilated renal pelvis only"], correctIndex: 0, rationale: "Acute renal vein thrombosis: kidney enlargement, diffuse hypoechogenicity, loss of corticomedullary differentiation, and echogenic thrombus in the renal vein with absent venous flow. Associated with nephrotic syndrome, dehydration, and RCC.", difficulty: 4, category: "Abdominal Sonography", topic: "Renal Masses" },
  { id: "sono-705", stem: "A nutcracker phenomenon on ultrasound refers to:", options: ["Compression of the left renal vein between the aorta and superior mesenteric artery causing elevated venous pressure","Right renal artery stenosis","Bilateral renal cysts","IVC thrombosis"], correctIndex: 0, rationale: "Nutcracker syndrome: the left renal vein is compressed between the SMA and aorta. Doppler shows elevated velocity at the compression point (>5:1 ratio with distal vein). Causes left flank pain, hematuria, and left varicocele in males.", difficulty: 4, category: "Abdominal Sonography", topic: "Renal Masses" },
];
